/*!40000 ALTER TABLE `vocabulary` DISABLE KEYS */;
INSERT INTO `vocabulary` VALUES (1,'A state of being fully aware and conscious of one\'s surroundings and thoughts; characterized by a clear and focused mental state.','https://www.oxfordlearnersdictionaries.com/definition/english/a_1','[\"After meditating for an hour, she achieved a state of profound mindfulness.\",\"The therapist encouraged him to practice mindfulness techniques to reduce his anxiety.\"]','a1','0-4','indefinite article','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/a__/a__us/a__us_2_rr.ogg','a','[\"awareness\",\"consciousness\",\"presence\"]',NULL,NULL,_binary '\0'),(2,'Abandon signifies to give up completely, cease to support, or forsake something, typically due to a loss of hope or strength.','https://www.oxfordlearnersdictionaries.com/definition/english/abandon_1','[\"The sailors abandoned ship after the violent storm.\",\"She abandoned her dreams of becoming a writer when faced with rejection.\"]','b2','5-6','verb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/aba/aband/abandon__us_2.ogg','abandon','[\"forsake\",\"desert\",\"relinquish\"]',NULL,NULL,_binary '\0'),(3,'The natural or acquired capacity to perform a specific task or function.','https://www.oxfordlearnersdictionaries.com/definition/english/ability_1','[\"The ability to speak multiple languages has been a valuable asset in her career.\",\"His exceptional ability to solve complex math problems has made him a renowned expert in the field.\"]','a2','0-4','noun','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abi/abili/ability__us_4.ogg','ability','[\"talent\",\"capacity\",\"aptitude\"]',_binary '\0',NULL,_binary '\0'),(4,'Having the power or ability to do something; capable.','https://www.oxfordlearnersdictionaries.com/definition/english/able_1','[\"He was able to finish the project on time.\",\"Despite the challenges, she was able to overcome them.\"]','a2','0-4','adjective','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abl/able_/able__us_2.ogg','able','[\"capable\",\"competent\",\"competent\"]',NULL,'/eɪbəl/',_binary '\0'),(5,'to do away with something, such as an institution, practice, or system, often in a formal or official manner','https://www.oxfordlearnersdictionaries.com/definition/english/abolish','[\"The government has announced plans to abolish the old tax laws and replace them with a new system.\",\"The organization has been working to abolish child labor practices for decades.\"]','c1','7-8','verb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abo/aboli/abolish__us_1.ogg','abolish',NULL,NULL,NULL,_binary '\0'),(6,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/abortion',NULL,'c1','7-8','noun','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abo/abort/abortion__us_1.ogg','abortion',NULL,NULL,NULL,_binary '\0'),(7,'Relating to or concerning a particular topic or subject; existing or occurring in a specified place or time.','https://www.oxfordlearnersdictionaries.com/definition/english/about_2','[\"I\'m reading a book about ancient Rome.\",\"She\'s always talking about her trip to Italy.\"]','a1','0-4','adverb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abo/about/about__us_1.ogg','about','[\"regarding\",\"concerning\",\"in relation to\"]',_binary '','/əˈbaʊt/”, [ˈɑːbt]',_binary '\0'),(8,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/about_1','[]','a1','0-4','preposition','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abo/about/about__us_1.ogg','about','[]',_binary '',NULL,_binary '\0'),(9,'Located or situated in a higher position than something else; extended upwards.','https://www.oxfordlearnersdictionaries.com/definition/english/above_2','[\"The plane flew above the clouds.\",\"He looked above for a solution to the problem.\"]','a1','0-4','adverb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abo/above/above__us_2.ogg','above','[\"over\",\"uppermost\",\"higher\"]',_binary '','/əˈbʌv/ ',_binary '\0'),(10,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/above_1',NULL,'a1','0-4','preposition','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abo/above/above__us_2.ogg','above',NULL,NULL,NULL,_binary '\0'),(11,'Located or extending beyond one\'s native country; in a foreign land.','https://www.oxfordlearnersdictionaries.com/definition/english/abroad','[\"After graduating, he decided to travel abroad for a year.\",\"The company is expanding its operations abroad, particularly in Asia.\"]','a2','0-4','adverb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abr/abroa/abroad__us_4.ogg','abroad','[\"overseas\",\"externally\",\"foreignly\"]',NULL,'/əˈbroʊd/',_binary '\0'),(12,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/absence',NULL,'c1','7-8','noun','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abs/absen/absence__us_1.ogg','absence',NULL,NULL,NULL,_binary '\0'),(13,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/absent_1',NULL,'c1','7-8','adjective','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abs/absen/absent__us_1.ogg','absent',NULL,NULL,NULL,_binary '\0'),(14,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/absolute_1',NULL,'b2','5-6','adjective','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abs/absol/absolute__us_1_rr.ogg','absolute',NULL,NULL,NULL,_binary '\0'),(15,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/absolutely',NULL,'b1','5-6','adverb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abs/absol/absolutely__us_1_rr.ogg','absolutely',NULL,NULL,NULL,_binary '\0'),(16,NULL,