,NULL,NULL,NULL,_binary '\0'),(24,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/academy',NULL,'c1','7-8','noun','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/aca/acade/academy__us_1.ogg','academy',NULL,NULL,NULL,_binary '\0'),(25,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/accelerate',NULL,'c1','7-8','verb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/accel/accelerate__us_1.ogg','accelerate',NULL,NULL,NULL,_binary '\0'),(26,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/accent_1',NULL,'b2','5-6','noun','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/accen/accent__us_1_rr.ogg','accent',NULL,NULL,NULL,_binary '\0'),(27,'To receive and acknowledge something willingly; to agree to or welcome.','https://www.oxfordlearnersdictionaries.com/definition/english/accept','[\"She accepted his apology with a smile.\",\"The company accepted the offer to merge with a competitor.\"]','a2','0-4','verb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/accep/accept__us_1.ogg','accept','[\"receive\",\"agree\",\"acknowledge\"]',NULL,'/əkˈsept/',_binary '\0'),(28,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/acceptable',NULL,'b2','5-6','adjective','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/accep/acceptable__us_3.ogg','acceptable',NULL,NULL,NULL,_binary '\0'),(29,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/acceptance',NULL,'c1','7-8','noun','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/accep/acceptance__us_1.ogg','acceptance',NULL,NULL,NULL,_binary '\0'),(30,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/access_1',NULL,'b1','5-6','noun','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/acces/access__us_2.ogg','access',NULL,NULL,NULL,_binary '\0'),(31,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/access_2',NULL,'b1','5-6','verb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/acces/access__us_2.ogg','access',NULL,NULL,NULL,_binary '\0'),(32,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/accessible',NULL,'c1','7-8','adjective','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/acces/accessible__us_1.ogg','accessible',NULL,NULL,NULL,_binary '\0'),(33,'An unfortunate event occurring by chance, resulting in damage, injury, or loss.','https://www.oxfordlearnersdictionaries.com/definition/english/accident','[\"The car accident caused significant damage to both vehicles.\",\"A slip and fall accident resulted in a serious injury.\"]','a2','0-4','noun','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/accid/accident__us_2_rr.ogg','accident','[\"misfortune\",\"casualty\",\"incident\"]',NULL,'/ˈæksɪdənt/',_binary '\0'),(34,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/accidentally',NULL,'b2','5-6','adverb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/accid/accidentally__us_1.ogg','accidentally',NULL,NULL,NULL,_binary '\0'),(35,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/accommodate',NULL,'b2','5-6','verb','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/accom/accommodate__us_1.ogg','accommodate',NULL,NULL,NULL,_binary '\0'),(36,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/accommodation',NULL,'b1','5-6','noun','word','https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/acc/accom/accommodation__us_2.ogg','accommodation',NULL,NULL,NULL,_binary '\0'),(37,NULL,'https://www.oxfordlearnersdictionaries.com/definition/english/accompany',NULL,'b2','5-6','verb','word','https://www.oxfordlearnersdict