d\",\"level\":\"a2\",\"levelGroup\":\"0-4\",\"pos\":\"noun\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/ability_1\",\"voiceUrl\":\"https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abi/abili/ability__us_4.ogg\"}',3),(7,'UPDATED',NULL,'2026-03-15 03:42:10.950801',4,'{\"id\":3,\"word\":\"ability\",\"type\":\"word\",\"level\":\"a2\",\"levelGroup\":\"0-4\",\"pos\":\"noun\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/ability_1\",\"voiceUrl\":\"https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abi/abili/ability__us_4.ogg\"}',3),(8,'AI_GENERATED',NULL,'2026-03-15 03:50:30.130225',4,'{\"id\":3,\"word\":\"ability\",\"type\":\"word\",\"level\":\"a2\",\"levelGroup\":\"0-4\",\"pos\":\"noun\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/ability_1\",\"voiceUrl\":\"https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abi/abili/ability__us_4.ogg\",\"definition\":\"The quality or state of having the power or capacity to do something; a natural or acquired skill or talent that enables someone to do something efficiently or effectively.\",\"examples\":[\"She showed a remarkable ability to learn new languages.\",\"His ability to think critically helped him solve the complex problem.\"],\"synonyms\":[\"aptitude\",\"capacity\",\"talent\"]}',3),(9,'AI_GENERATED',NULL,'2026-03-15 03:50:31.394866',4,'{\"id\":3,\"word\":\"ability\",\"type\":\"word\",\"level\":\"a2\",\"levelGroup\":\"0-4\",\"pos\":\"noun\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/ability_1\",\"voiceUrl\":\"https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abi/abili/ability__us_4.ogg\",\"definition\":\"The natural or acquired capacity to do something; a skill, talent, or faculty.\",\"examples\":[\"Her ability to speak multiple languages helped her navigate the foreign country.\",\"The team\'s ability to work together efficiently was crucial to their success.\"],\"synonyms\":[\"capacity\",\"talent\",\"aptitude\"]}',3),(10,'UPDATED',NULL,'2026-03-15 03:50:56.243033',4,'{\"id\":3,\"word\":\"ability\",\"type\":\"word\",\"level\":\"a2\",\"levelGroup\":\"0-4\",\"pos\":\"noun\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/ability_1\",\"voiceUrl\":\"https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abi/abili/ability__us_4.ogg\",\"definition\":\"the natural or acquired capacity to do something efficiently and effectively\",\"examples\":[\"The company valued her exceptional ability to manage projects efficiently.\",\"He developed a remarkable ability to play the piano with perfect pitch.\"],\"synonyms\":[]}',3),(11,'UPDATED',NULL,'2026-03-15 03:51:20.299486',4,'{\"id\":3,\"word\":\"ability\",\"type\":\"word\",\"level\":\"a2\",\"levelGroup\":\"0-4\",\"pos\":\"noun\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/ability_1\",\"voiceUrl\":\"https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abi/abili/ability__us_4.ogg\",\"definition\":\"the natural or acquired capacity to do something efficiently and effectively yes\",\"examples\":[\"The company valued her exceptional ability to manage projects efficiently.\",\"He developed a remarkable ability to play the piano with perfect pitch.\"],\"synonyms\":[]}',3),(12,'AI_GENERATED',NULL,'2026-03-15 03:56:58.244631',4,'{\"id\":2,\"word\":\"abandon\",\"type\":\"word\",\"level\":\"b2\",\"levelGroup\":\"5-6\",\"pos\":\"verb\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/abandon_1\",\"voiceUrl\":\"https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/aba/aband/abandon__us_2.ogg\",\"definition\":\"to give up or surrender something, especially a place, person, or interest, usually without intending to return to it; to leave or desert something\",\"examples\":[\"The hikers were forced to abandon their trek when a landslide blocked their path\",\"The company abandoned its plans to build a new factory due to financial difficulties\"],\"synonyms\":[\"desert\",\"leave behind\",\"quit\"]}',2),(13,'UPDATED',NULL,'2026-03-15 03:57:48.997117',4,'{\"id\":2,\"word\":\"abandon\",\"type\":\"word\",\"level\":\"b2\",\"levelGroup\":\"5-6\",\"pos\":\"verb\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/abandon_1\",\"voiceUrl\":\"https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/aba/aband/abandon__us_2.ogg\",\"definition\":\"to leave or surrender something or someone, typically in a state of disrepair or without care, or to give up or stop doing something\",\"examples\":[\"The company abandoned its struggling subsidiary and focused on more profitable ventures.\",\"After a year of struggling to find a job, she decided to abandon her search and take a break.\"],\"synonyms\":[]}',2),(14,'AI_GENERATED',NULL,'2026-03-15 04:08:38.711814',4,'{\"id\":3,\"word\":\"ability\",\"type\":\"word\",\"level\":\"a2\",\"levelGroup\":\"0-4\",\"pos\":\"noun\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/ability_1\",\"voiceUrl\":\"https://www.oxfordlearnersdictionaries.com/media/english/us_pron_ogg/a/abi/abili/ability__us_4.ogg\",\"definition\":\"The quality or state of being able to do something; a natural or acquired skill or talent that enables one to perform a specific task or activity.\",\"examples\":[\"The child\'s ability to solve puzzles was impressive.\",\"The company\'s ability to adapt to changing market conditions was a major factor in its success.\"],\"synonyms\":[\"capacity\",\"talent\",\"gift\"]}',3),(15,'AI_GENERATED',NULL,'2026-03-15 04:08:39.051477',4,'{\"id\":3,\"word\":\"ability\",\"type\":\"word\",\"level\":\"a2\",\"levelGroup\":\"0-4\",\"pos\":\"noun\",\"definitionUrl\":\"https://www.oxfordlearnersdictionaries.com/definition/english/ability_1\",\"voiceUrl\